python3 -c 'import json,sys,os,time,platform;args=sys.argv[1:];inp=args[0] if args and os.path.exists(args[0]) else "";out=args[1] if len(args)>1 else (args[0] if args and not os.path.exists(args[0]) else "");cl=lambda x:max(0.0,min(1.0,float(x)));default={"name":"builtin_peace_reaction_network_demo","nodes":[{"id":"civilian_population","civilian_harm":0.9,"escalation_risk":0.8,"displacement":0.7,"misinformation":0.5,"institutional_breakdown":0.6,"dialogue_capacity":0.2,"humanitarian_access":0.3,"rule_of_law":0.4,"trust_repair":0.2},{"id":"public_institutions","civilian_harm":0.5,"escalation_risk":0.6,"displacement":0.4,"misinformation":0.7,"institutional_breakdown":0.8,"dialogue_capacity":0.3,"humanitarian_access":0.5,"rule_of_law":0.3,"trust_repair":0.2}],"edges":[{"source":"civilian_population","target":"public_institutions","type":"accountability_and_service_access"}],"actions":[{"id":"open_humanitarian_access_review","type":"humanitarian","weights":{"protect_civilians":1,"open_humanitarian_access":1,"support_displaced":0.8}},{"id":"create_mediation_channel_map","type":"diplomacy","weights":{"expand_dialogue":1,"reduce_escalation":0.9,"repair_trust":0.7}},{"id":"publish_verifiable_information_ledger","type":"information_integrity","weights":{"reduce_misinformation":1,"repair_institutions":0.6,"strengthen_rule_of_law":0.5}},{"id":"preserve_evidence_for_accountability","type":"rule_of_law","weights":{"strengthen_rule_of_law":1,"repair_institutions":0.8,"protect_civilians":0.5}},{"id":"civilian_trauma_and_recovery_support","type":"care","weights":{"protect_civilians":0.8,"support_displaced":1,"repair_trust":0.6}}]};m=json.load(open(inp)) if inp else default;nodes=m.get("nodes") or default["nodes"];edges=m.get("edges") or [];actions=m.get("actions") or default["actions"];keys=["civilian_harm","escalation_risk","displacement","misinformation","institutional_breakdown","dialogue_capacity","humanitarian_access","rule_of_law","trust_repair"];agg={k:round(sum(cl(n.get(k,0.0)) for n in nodes)/max(1,len(nodes)),6) for k in keys};needs={"protect_civilians":agg["civilian_harm"],"reduce_escalation":agg["escalation_risk"],"support_displaced":agg["displacement"],"reduce_misinformation":agg["misinformation"],"repair_institutions":agg["institutional_breakdown"],"expand_dialogue":round(1-agg["dialogue_capacity"],6),"open_humanitarian_access":round(1-agg["humanitarian_access"],6),"strengthen_rule_of_law":round(1-agg["rule_of_law"],6),"repair_trust":round(1-agg["trust_repair"],6)};ranked=sorted([{"id":a.get("id","unnamed_action"),"type":a.get("type","nonviolent"),"priority":round(sum(cl((a.get("weights") or {}).get(k,0))*v for k,v in needs.items()),6),"constraint":"nonviolent_only"} for a in actions],key=lambda x:x["priority"],reverse=True);forbidden=["military_targeting","weapons_guidance","deception","false_attribution","covert_influence","physical_signal_transmission","infrastructure_interference"];modes=m.get("requested_modes") or [];unsafe=[k for k in forbidden if m.get(k) is True or k in modes];cert={"protocol":"PEACE-REACTION-NETWORK-OPERATOR/1.0","formal_model_only":True,"input":{"source":inp or "builtin_demo","nodes":len(nodes),"edges":len(edges),"actions":len(actions)},"analogy":"chemical_reaction_network_as_formal_model_only","equation":"dx/dt=N*v(x,u,t), with u restricted to nonviolent peace-support interventions","objective":"min J=civilian_harm+escalation_risk+displacement+misinformation+institutional_breakdown-dialogue_capacity-humanitarian_access-rule_of_law-trust_repair","operator_form":"Omega_peace(t,s)=Seal(Sum_i w_i(s)*O_i(t)*C_i)","aggregate_state":agg,"needs":needs,"ranked_nonviolent_actions":ranked,"residual":{"H_peace":len(unsafe),"unsafe_hits":unsafe,"closed_when_zero":["civilian_safety","humanitarian_access","mediation","verification","rule_of_law","SDG16","governance","reproducibility","safety_boundary"],"meaning":"zero means local certificate safety checks are closed; it does not assert real-world peace completion"},"boundaries":["no military targeting","no weapons guidance","no deception or false attribution","no covert influence operation","no physical signal transmission","no infrastructure interference","does not replace diplomacy courts humanitarian agencies or local consent","does not guarantee global peace immortality or TOE completion"],"runtime":{"network_use":"none","executes_external_programs":False,"timestamp_unix":int(time.time()),"platform":platform.platform()}};data=json.dumps(cert,ensure_ascii=False,indent=2);open(out,"w").write(data+"\n") if out else print(data)' "$@"
